const p = $input.first().json;
let q = [];
if (p.sender) q.push('from:' + p.sender);
if (p.keyword) q.push(p.keyword);
if (p.label) q.push('label:' + p.label);
if (p.is_unread === true) q.push('is:unread');
if (p.has_attachment === true) q.push('has:attachment');
if (p.date_from) q.push('after:' + p.date_from);
if (p.date_to) q.push('before:' + p.date_to);
if (p.subject) q.push('subject:' + p.subject);
const searchQuery = q.join(' ') || 'in:inbox';
return [{ json: { search_query: searchQuery, limit: p.limit || 20 } }];

const results = $input.all().map(item => {
  const j = item.json;
  const headers = j.payload?.headers || [];
  const getHeader = (name) => {
    const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase());
    return h ? h.value : '';
  };
  return {
    json: {
      message_id: j.id || '',
      thread_id: j.threadId || '',
      sender: getHeader('From'),
      subject: getHeader('Subject'),
      snippet: j.snippet || '',
      date: getHeader('Date'),
      labels: (j.labelIds || []).join(','),
      is_unread: (j.labelIds || []).includes('UNREAD'),
      has_attachments: (j.payload?.parts || []).some(p => p.filename && p.filename.length > 0)
    }
  };
});
return results.length > 0 ? results : [{ json: { message: 'No results found' } }];
